args.sparql:
SELECT ?firstFilm WHERE {
  ?award rdfs:label "Best New Filmmaker"@en ;
         wdt:P585 ?awardDate ;
         wdt:P1343 ?awardFilm .
  FILTER (SUBSTR(STR(?awardDate), 1, 4) = "1999") .
  ?awardFilm wdt:P57 ?person .
  ?firstFilm wdt:P57 ?person .
  ?firstFilm wdt:P577 ?releaseDate .
} ORDER BY ?releaseDate LIMIT 1
